const { Manifold, label } = api;

// Icosahedron vertices: cyclic permutations of (0, +/-1, +/-phi)
// phi = golden ratio = (1 + sqrt(5)) / 2 ~ 1.6180339887
const phi = (1 + Math.sqrt(5)) / 2;
const scale = 9; // scale factor so largest dim ~18 units

// All 12 icosahedron vertices (normalized)
const rawVerts = [
  [0, 1, phi],
  [0, -1, phi],
  [0, 1, -phi],
  [0, -1, -phi],
  [1, phi, 0],
  [-1, phi, 0],
  [1, -phi, 0],
  [-1, -phi, 0],
  [phi, 0, 1],
  [-phi, 0, 1],
  [phi, 0, -1],
  [-phi, 0, -1],
];

// Normalize and scale: each vertex at distance sqrt(1 + phi^2) from origin
const len = Math.sqrt(1 + phi * phi);
const verts = rawVerts.map(([x, y, z]) => [
  x / len * scale,
  y / len * scale,
  z / len * scale,
]);

// Hull of small spheres at each vertex = icosahedron
const spheres = verts.map(v => Manifold.sphere(0.5, 4).translate(v));
const d20 = label(Manifold.hull(spheres), 'body');

return d20;
